class Solution:
    def memLeak(self, memory1, memory2):
        """
        :type memory1: int
        :type memory2: int
        :rtype: List[int]
        """
        second = 1

        while memory1 >= second or memory2 >= second:
            if memory1 >= memory2:
                memory1 -= second
            else:
                memory2 -= second
            second += 1

        return [second, memory1, memory2]
